const body = $input.item.json.body;
if (!body.doc_type || !body.warehouse_code || !body.created_by) {
  return { json: { _error: true, success: false, message: '缺少必要字段: doc_type, warehouse_code, created_by' } };
}
const type = body.doc_type;
if (type !== 'IC' && type !== 'LM') {
  return { json: { _error: true, success: false, message: '只有IC和LM类型可以在WMS中创建' } };
}
const now = new Date();
const dateStr = now.getFullYear() + String(now.getMonth()+1).padStart(2,'0') + String(now.getDate()).padStart(2,'0');
const prefix = type + dateStr;
return { json: { _error: false, type: type, prefix: prefix, warehouse: body.warehouse_code, user: body.created_by, remarks: body.remarks || '' } };

const prev = $('Validate Create').first().json;
// seq_num: ON CONFLICT 时 RETURNING next_val 返回递增值
// 首次 INSERT 时 RETURNING 返回初始值1
const seqNum = $input.first().json.seq_num || 1;
const docNumber = prev.prefix + String(seqNum).padStart(3, '0');
return { json: { ...prev, doc_number: docNumber } };

const body = $input.item.json.body;
if (!body.doc_number || !body.doc_type) {
  return { json: { _error: true, success: false, message: '缺少doc_number或doc_type' } };
}
return { json: { _error: false, doc_number: body.doc_number, doc_type: body.doc_type, performed_by: body.performed_by || '' } };

const body = $input.item.json.body;
if (!body.ids || !Array.isArray(body.ids) || body.ids.length === 0) {
  return { json: { _error: true, success: false, message: '缺少ids数组' } };
}
const ids = body.ids.map(function(id) { return parseInt(id); }).filter(function(id) { return !isNaN(id); });
if (ids.length === 0) {
  return { json: { _error: true, success: false, message: 'ids必须包含有效的数字ID' } };
}
return { json: { _error: false, ids: ids, idList: ids.join(',') } };
